SELECT WORK_SEQ, (CASE WORK_ID WHEN 'Message' THEN '전문' WHEN 'Trx' THEN '거래' WHEN 'P_SERVICE' THEN '웹 서비스' WHEN 'B_Service' THEN '업무 서비스' WHEN 'UI_LAYOUT' THEN '레이아웃' WHEN 'P_Component' THEN '웹 컴포넌트' WHEN 'B_Component' THEN '업무 컴포넌트' WHEN 'P_POPUP' THEN '팝업관리' WHEN 'SQL_QUERY' THEN 'SQL쿼리관리' WHEN 'SQL_CONF' THEN '데이터소스관리' WHEN 'SQL_GROUP' THEN 'SQL그룹관리' WHEN 'P_TEMPLET' THEN '템플릿관리' WHEN 'P_BIZ_GROUP' THEN '하위그룹' WHEN 'Errorcode' THEN '에러코드' WHEN 'Codegroup' THEN '코드그룹' WHEN 'BoardTemplet_Service' THEN '게시판템플릿' WHEN 'Board_Service' THEN '게시판' WHEN 'BANNER' THEN '배너' WHEN 'BANNER_AREA' THEN '배너영역' WHEN 'CAMPAIGN' THEN '캠페인' ELSE WORK_ID END) AS WORK_ID, WORK_ID AS WORK_ORI_ID, WORK_DATA_PK, WORK_NAME, (CASE CRUD_TYPE WHEN 'C' THEN '생성' WHEN 'R' THEN '조회' WHEN 'U' THEN '수정' WHEN 'D' THEN '삭제' ELSE CRUD_TYPE END) AS CRUD_TYPE, NVL(APPROVAL_SEQ, '결재미신청') AS APPROVAL_SEQ, LAST_UPDATE_USER_ID, NVL(DIST_YN, 'N') AS DIST_YN, DIST_DTIME, GROUP_ID, FILE_NAME, NVL2(APPROVAL_SEQ, 'N', 'Y') AS DELETE_YN, TO_CHAR( TO_DATE(LAST_UPDATE_DTIME, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) AS LAST_UPDATE_DTIME FROM FWK_WORK_LIST WHERE GROUP_ID LIKE #{userId} || '%' AND LENGTH(#{userId}) + 3 = LENGTH(GROUP_ID)
AND GROUP_ID = #{groupId}
ORDER BY LAST_UPDATE_DTIME DESC

